func TestGetExtendedParticipantList(t *testing.T) {

	code := ""
	data := ""
	config := ""

	electorAccountID := ton.MustParseAccountID("-1:3333333333333333333333333333333333333333333333333333333333333333")
	e, err := tvm.NewEmulatorFromBOCsBase64(code, data, config)
	if err != nil {
		t.Fatalf("NewEmulatorFromBOCsBase64() failed: %v", err)
	}
	participants, err := GetParticipantListExtended(context.Background(), e, electorAccountID)
	if err != nil {
		t.Fatalf("GetParticipantListExtended() failed: %v", err)
	}
	if len(participants.Validators) != 316 {
		t.Fatalf("got: %v, want: 316", len(participants.Validators))
	}
	pubkeys := make(map[string]struct{})
	for _, validator := range participants.Validators {
		if validator.V1.Stake < math.MaxInt32 {
			t.Fatalf("stake looks too low: %v", validator.V1.Stake)
		}
		if validator.V1.MaxFactor != 196608 {
			t.Fatalf("got: %v, want: 196608", validator.V1.MaxFactor)
		}
		pubkey := validator.V0.HexString()
		if _, ok := pubkeys[pubkey]; ok {
			t.Fatalf("two validators have the same pubkey")
		}
		pubkeys[pubkey] = struct{}{}
	}
}

func TestDecodeStorage(t *testing.T) {
	cell := boc.MustDeserializeSinglRootBase64("")

	var storage ElectorStorage
	require.NoError(t, storage.UnmarshalTLB(cell, tlb.NewDecoder()))
	return
}
